import { getState, subscribe } from '../../state.js';
import { div } from '../../../utils/createElement.js';

export function createSpeedometerScreen(){

const START_ANGLE = Math.PI /1.35 + 0.3;  // ajuste fino real
  const END_ANGLE = Math.PI * 2 + 0.63;// calibrado para casar com escala visual 0..200 do fundo
  const SIZE = 500;
  const CX = SIZE / 2.2;
  const CY = SIZE / 2.24;
  const R = 120;
  const MAX = 200;
const SPEED_CALIBRATION_MULTIPLIER = 1.038;
const SPEED_CALIBRATION_OFFSET = 2.3;

  // 🔥 COLE SEU BASE64 AQUI
  const BASE64_IMAGE = "data:image/png;base64,";

  const container = div({});
  container.style.cssText = `
    width:${SIZE}px;
    height:${SIZE}px;
    position:relative;
    background:transparent;
    border:none;
    pointer-events:none;
  `;

  // ===== FUNDO (IMAGEM) =====
  const bgImg = document.createElement("img");
  bgImg.src = BASE64_IMAGE;
  bgImg.style.cssText = `
    position:absolute;
    left:-23px;
    top:-40px;
    width:500px;
    height:500px;
    object-fit:cover;
  `;

  // ===== CANVAS FX =====
  const canvas = document.createElement("canvas");
  canvas.width = SIZE;
  canvas.height = SIZE;
  canvas.style.position = "absolute";

  const ctx = canvas.getContext("2d");

  // ===== DISPLAY =====
  const display = document.createElement("div");
  display.style.cssText = `
    position:absolute;
    bottom:20px;
    left:0px;
    width:100%;
    text-align:center;
    color:white;
  `;

  const speedText = document.createElement("div");
  speedText.style.fontSize = "120px";
  speedText.style.fontWeight = "300";

  const unit = document.createElement("div");
  unit.innerText = "km/h";
  unit.style.opacity = "0.4";
  unit.style.cssText = `
    position:absolute;
    bottom:30px;
    width:100%;
    text-align:center;
    opacity:0.4;
  `;

  display.appendChild(speedText);
  display.appendChild(unit);

  let speed = 0;

  // ===== PARTÍCULAS (SÓ NAS PONTAS) =====
  const particles = Array.from({length:30}).map(() => ({
  t: Math.random(),        // posição no arco (0 → 1)
  speed: 0.002 + Math.random()*0.003,
  size: 1 + Math.random()*2
}));
function mapSpeed(speed){

  const map = [
    {s: 0,   a: 0.00},
    {s: 20,  a: 0.105},
    {s: 40,  a: 0.220},
    {s: 60,  a: 0.335},
    {s: 80,  a: 0.447},
    {s: 100, a: 0.560}, 
    {s: 120, a: 0.680},
    {s: 140, a: 0.816},
    {s: 160, a: 0.894},
    {s: 200, a: 0.975}
  ];

  for(let i=0;i<map.length-1;i++){
    const p1 = map[i];
    const p2 = map[i+1];

    if(speed >= p1.s && speed <= p2.s){
      const t = (speed - p1.s) / (p2.s - p1.s);
      return p1.a + t * (p2.a - p1.a);
    }
  }

  return 1;
}
function drawArcEnergy(){

const ratio = mapSpeed(speed);
  const startAngle = START_ANGLE;
  const endAngle = START_ANGLE + ratio * (END_ANGLE - START_ANGLE);

  const hue = 120 - (ratio * 120);

  // =========================
  // 🔥 1. GLOW CONTÍNUO
  // =========================
  ctx.beginPath();
  ctx.arc(CX, CY, R, startAngle, endAngle);

  ctx.strokeStyle = `hsla(${hue},100%,60%,0.5)`;
  ctx.lineWidth = 30;

  ctx.shadowBlur = 25;
  ctx.shadowColor = `hsla(${hue},100%,60%,0.8)`;

  ctx.stroke();

  ctx.shadowBlur = 0;

  // =========================
  // ⚡ 2. PARTÍCULAS
  // =========================
  particles.forEach((p, i) => {

    p.t += p.speed;
    if(p.t > 1) p.t = 0;

    const t = p.t;

    const angle = startAngle + t * (endAngle - startAngle);

    const x = CX + Math.cos(angle) * R;
    const y = CY + Math.sin(angle) * R;

    ctx.beginPath();
    ctx.arc(x, y, p.size, 0, Math.PI * 2);

    ctx.fillStyle = `hsla(${hue},100%,70%,0.9)`;

    ctx.shadowBlur = 15;
    ctx.shadowColor = ctx.fillStyle;

    ctx.fill();
  });

  ctx.shadowBlur = 0;

  // =========================
  // 💥 3. BOOST NO FINAL
  // =========================
  const boostAngle = endAngle;

  const bx = CX + Math.cos(boostAngle) * R;
  const by = CY + Math.sin(boostAngle) * R;

  ctx.beginPath();
  ctx.arc(bx, by, 6, 0, Math.PI * 2);

  ctx.fillStyle = `hsla(${hue},100%,70%,1)`;

  ctx.shadowBlur = 30;
  ctx.shadowColor = ctx.fillStyle;

  ctx.fill();

  ctx.shadowBlur = 0;
}

  // ===== PONTEIRO REAL =====
 function drawNeedle(){

  const ratio = mapSpeed(speed);
  const angle = START_ANGLE + ratio * (END_ANGLE - START_ANGLE);

  ctx.save();

  // 🔥 move para o centro REAL
  ctx.translate(CX, CY);

  // 🔥 gira o canvas
  ctx.rotate(angle);

  // =========================
  // DESENHA SEMPRE NA MESMA POSIÇÃO
  // =========================

  const length = R - 30;

  const grad = ctx.createLinearGradient(0, 0, length, 0);
  grad.addColorStop(0, "white");
  grad.addColorStop(1, "red");

  ctx.beginPath();
  ctx.moveTo(0, 0);       // 🔥 sempre centro
  ctx.lineTo(length, 0);  // 🔥 sempre horizontal

  ctx.strokeStyle = grad;
  ctx.lineWidth = 3;

  ctx.shadowBlur = 20;
  ctx.shadowColor = "red";

  ctx.stroke();

  ctx.shadowBlur = 0;

  ctx.restore();

  // =========================
  // HUB (fora da rotação)
  // =========================

  ctx.beginPath();
  ctx.arc(CX, CY, 14, 0, Math.PI*2);
  ctx.strokeStyle = "rgba(255,255,255,0)";
  ctx.stroke();

  ctx.beginPath();
  ctx.arc(CX, CY, 25, 0, Math.PI*2);
  ctx.strokeStyle = "red";
  ctx.lineWidth = 3;
  ctx.shadowBlur = 22;
  ctx.shadowColor = "red";
  //ctx.stroke();

  ctx.shadowBlur = 0;
}

  // ===== LOOP =====
  function loop(){

    ctx.clearRect(0,0,SIZE,SIZE);

    drawArcEnergy();
    drawNeedle();

    rafId = requestAnimationFrame(loop);
  }

  function update(v){
    const raw = Number(v);
    const normalized = Number.isFinite(raw) ? raw : 0;
    const calibrated = normalized > 0
      ? (normalized * SPEED_CALIBRATION_MULTIPLIER) + SPEED_CALIBRATION_OFFSET
      : 0;
    speed = Math.max(0, Math.min(MAX, calibrated));
    // Keep displayed numeral exactly aligned with Normal mode source (carSpeed).
    const displayValue = (v === null || v === undefined || Number.isNaN(raw)) ? 0 : v;
    speedText.innerText = String(displayValue);
  }

  let rafId = null;
  loop();

  const unsub = subscribe("carSpeed", update);
  update(getState("carSpeed") || 0);

  container.appendChild(bgImg);
  container.appendChild(canvas);
  container.appendChild(display);

  return {
    element: container,
    cleanup: () => {
      if (rafId) cancelAnimationFrame(rafId);
      unsub();
    }
  };
} 
